import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a home equity loan?", a: "A home equity loan lets you borrow a lump sum against the equity in your home, usually with a fixed interest rate and fixed monthly payment." },
  { q: "How much can you borrow with a home equity loan?", a: "Many lenders cap total borrowing around 80% to 85% of your home's value after including your current mortgage balance." },
  { q: "What is LTV ratio?", a: "LTV means loan-to-value ratio. It compares your total mortgage debt to your home's value as a percentage." },
  { q: "What is the difference between a home equity loan and HELOC?", a: "A home equity loan pays one lump sum with fixed payments. A HELOC is a revolving line of credit you can draw from during a set period." },
  { q: "Is home equity loan interest tax deductible?", a: "Interest may be deductible when the loan is used to buy, build, or substantially improve the home securing the loan. Tax rules can change, so confirm with a tax professional." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function pmt(principal: number, rate: number, years: number) {
  const r = rate / 100 / 12;
  const n = years * 12;
  if (principal <= 0 || n <= 0) return 0;
  return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n));
}

export default function HomeEquityLoanCalculator() {
  useCurrencyVersion();
  const [homeValue, setHomeValue] = useState(400000);
  const [mortgageBalance, setMortgageBalance] = useState(240000);
  const [desiredLoan, setDesiredLoan] = useState(60000);
  const [rate, setRate] = useState(8);
  const [years, setYears] = useState(10);

  const result = useMemo(() => {
    const availableEquity = Math.max(0, homeValue - mortgageBalance);
    const maxLoan = Math.max(0, homeValue * 0.85 - mortgageBalance);
    const usableLoan = Math.min(Math.max(0, desiredLoan), maxLoan);
    const monthly = pmt(usableLoan, rate, years);
    const totalInterest = Math.max(0, monthly * years * 12 - usableLoan);
    const ltv = homeValue > 0 ? ((mortgageBalance + usableLoan) / homeValue) * 100 : 0;
    return { availableEquity, maxLoan, usableLoan, monthly, totalInterest, ltv };
  }, [homeValue, mortgageBalance, desiredLoan, rate, years]);

  const rows = [200000, 300000, 400000, 500000, 750000].map((value) => {
    const balance = value * 0.55;
    const maxLoan = Math.max(0, value * 0.85 - balance);
    return [value, balance, value - balance, maxLoan, pmt(maxLoan, 8, 10)] as const;
  });

  return (
    <>
      <SEOHead title="Free Home Equity Loan Calculator Online - Calculate How Much You Can Borrow Instantly | CalcHive" description="Free online home equity loan calculator. Calculate available equity, maximum loan amount and monthly payments for any home value and mortgage balance instantly. 100% free, no signup required." canonical="/home-equity-loan-calculator" keywords="free home equity loan calculator, home equity calculator free online, how much can I borrow home equity free, HEL calculator free, home equity borrowing calculator free" category="Financial Calculators" breadcrumbName="Free Home Equity Loan Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Home Equity Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate available home equity, maximum borrowing power, LTV, payment, and total interest.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Home value</label><input type="number" value={homeValue} onChange={(e) => setHomeValue(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Mortgage balance</label><input type="number" value={mortgageBalance} onChange={(e) => setMortgageBalance(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Desired loan amount</label><input type="number" value={desiredLoan} onChange={(e) => setDesiredLoan(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Loan term years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated Monthly Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.monthly)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Available equity</p><p className="text-lg font-extrabold text-foreground">{money(result.availableEquity)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Max loan at 85% LTV</p><p className="text-lg font-extrabold text-foreground">{money(result.maxLoan)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">New LTV</p><p className="text-lg font-extrabold text-foreground">{result.ltv.toFixed(1)}%</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Your Home Equity and Borrowing Power for Free</h2><p className="text-muted-foreground leading-relaxed">Subtract your mortgage balance from your estimated home value to find equity. Many lenders then limit total loans to about 85% of home value.</p><h2 className="text-2xl font-bold text-foreground">Home Equity Loan vs HELOC - What Is the Difference</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Home Equity Borrowing Capacity by Home Value and Balance</caption><thead className="bg-muted/60"><tr>{["Home Value", "Mortgage Balance", "Available Equity", "Max Loan (85% LTV)", "Monthly Payment at 8% 10yr"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row[0]}><td className="py-2.5 px-3 font-semibold">{money(row[0], 0)}</td><td className="py-2.5 px-3">{money(row[1], 0)}</td><td className="py-2.5 px-3">{money(row[2], 0)}</td><td className="py-2.5 px-3">{money(row[3], 0)}</td><td className="py-2.5 px-3">{money(row[4])}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Home Equity Calculator for Homeowners</h2><p className="text-muted-foreground leading-relaxed">Use this estimate to understand your borrowing range before requesting official loan quotes.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/home-equity-loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


